import json
import sys
from db_access import search_skills_by_tags

def execute(inputs):
    """Match sub-objectives to existing skills."""
    sub_objectives = inputs.get('sub_objectives', [])
    if isinstance(sub_objectives, str):
        try:
            sub_objectives = json.loads(sub_objectives)
        except json.JSONDecodeError:
            sub_objectives = []
    if not isinstance(sub_objectives, list):
        sub_objectives = []

    plan = []
    for obj in sub_objectives:
        if not isinstance(obj, dict):
            continue

        desc = obj.get('description', '')
        # Build search tags from domain_tags + keywords from description
        search_tags = list(obj.get('domain_tags', []))
        # Add keywords from description for better matching
        for word in desc.lower().replace('_', ' ').split():
            if len(word) > 3 and word not in ('from', 'with', 'that', 'this', 'into', 'will'):
                search_tags.append(word)

        # Check for explicit reuse
        if obj.get('reuse_skill_id'):
            plan.append({
                'sub_objective': desc,
                'action': 'execute_existing',
                'skill_id': obj['reuse_skill_id']
            })
            print(f'  [match_skills] Reusing skill by ID: {obj["reuse_skill_id"]}', file=sys.stderr)
            continue

        # Search for matching skills (threshold: 0.3 for combined tag+keyword)
        matches = search_skills_by_tags(search_tags, min_confidence=0.3)
        if matches:
            best = matches[0]
            plan.append({
                'sub_objective': desc,
                'action': 'execute_existing',
                'skill_id': best['skill_id']
            })
            print(f'  [match_skills] Matched: "{desc[:60]}" → skill "{best["name"]}" (confidence: {best["confidence"]})', file=sys.stderr)
        else:
            plan.append({
                'sub_objective': desc,
                'action': 'build_new_skill',
                'context': obj
            })
            print(f'  [match_skills] No match for: "{desc[:60]}" — will build new skill', file=sys.stderr)
    return {'execution_plan': plan}

outputs = execute(inputs)

