def test_match_skills_empty():
    result = execute({'sub_objectives': []})
    assert result['execution_plan'] == []

def test_match_skills_with_reuse():
    result = execute({'sub_objectives': [{'description': 'test', 'reuse_skill_id': 's1'}]})
    assert result['execution_plan'][0]['action'] == 'execute_existing'
